const API_BASE_URL = '/api';
async function fetchPricingConfigs() {
    try {
        const response = await fetch(`${API_BASE_URL}/pricingConfigs`, {
            method: 'GET',
            headers: {
                'Content-Type': 'application/json'
            }
        });
        if (!response.ok) throw new Error('Failed to fetch pricing configs');
        return await response.json();
    } catch (error) {
        console.error('Error fetching pricing configs:', error);
        return [];
    }
}
async function fetchPricingConfigById(id) {
    try {
        const response = await fetch(`${API_BASE_URL}/pricingConfigs/${id}`, {
            method: 'GET',
            headers: {
                'Content-Type': 'application/json'
            }
        });
        if (!response.ok) throw new Error('Failed to fetch pricing config');
        return await response.json();
    } catch (error) {
        console.error('Error fetching pricing config:', error);
        return null;
    }
}
async function savePricingConfig(data) {
    try {
        const response = await fetch(`${API_BASE_URL}/pricingConfigs`, {
            method: 'POST',
            headers: {
                'Content-Type': 'application/json'
            },
            body: JSON.stringify(data)
        });
        if (!response.ok) {
            const errorData = await response.json().catch(()=>({}));
            throw new Error(errorData.message || 'Failed to save pricing configuration');
        }
        const result = await response.json();
        return {
            success: true,
            data: result
        };
    } catch (error) {
        console.error('Error saving pricing config:', error);
        return {
            success: false,
            error: error.message
        };
    }
}
